import subprocess

def executeCommand():
    command_line = input().strip()
    if any(char in command_line for char in [';', '&', '|', '`', '(', ')', '{', '}']):
        return
    try:
        parts = shlex.split(command_line)
    except ValueError:
        return
    try:
        subprocess.run(parts, check=True)
    except subprocess.CalledProcessError:
        pass
    except Exception:
        pass

